class BankAccount {
private:
    double balance;
public:
    BankAccount(double initial) { balance = initial; }
    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
        }
    }
    double getBalance() { return balance; }
};

BankAccount acc(1000);
acc.deposit(-500);
cout << acc.getBalance();

class Temperature {
private:
